1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Step = { op: "quote"; items: Item[] };
3	type Customer = { yearsWithMHPCO: number };
4	type Input = { customer: Customer; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
8	const CURSE_SURCHARGE_PERCENT = 50;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
11	const LOYALTY_THRESHOLD_YEARS = 2;
12	const LOYALTY_DISCOUNT_PERCENT = 20;
13	const COMPONENT_BLOCK_SIZE = 3;
14	const COMPONENT_BLOCK_PREMIUM = 60;
15	
16	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	
27	const groupBaseAmount = (type: string, count: number): number => {
28	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
29	    return COMPONENT_BLOCK_PREMIUM;
30	  }
31	  return count * BASE_PREMIUM_BY_TYPE[type];
32	};
33	
34	const countByType = (items: Item[]): Map<string, number> =>
35	  items.reduce(
36	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
37	    new Map<string, number>(),
38	  );
39	
40	const basePremium = (items: Item[]): number =>
41	  Array.from(countByType(items)).reduce(
42	    (total, [type, count]) => total + groupBaseAmount(type, count),
43	    0,
44	  );
45	
46	const percentOf = (amount: number, percent: number): number =>
47	  (amount * percent) / 100;
48	
49	const percentOfItemBase = (item: Item, percent: number): number =>
50	  percentOf(BASE_PREMIUM_BY_TYPE[item.type], percent);
51	
52	const firstInsuranceSurcharge = (base: number): number =>
53	  Math.ceil(percentOf(base, FIRST_INSURANCE_SURCHARGE_PERCENT));
54	
55	const curseSurcharge = (item: Item): number =>
56	  item.cursed ? percentOfItemBase(item, CURSE_SURCHARGE_PERCENT) : 0;
57	
58	const highEnchantmentSurcharge = (item: Item): number =>
59	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
60	    ? percentOfItemBase(item, HIGH_ENCHANTMENT_SURCHARGE_PERCENT)
61	    : 0;
62	
63	const itemSurcharges = (items: Item[]): number =>
64	  items.reduce((sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item), 0);
65	
66	const loyaltyDiscount = (base: number, customer: Customer): number =>
67	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
68	    ? percentOf(base, LOYALTY_DISCOUNT_PERCENT)
69	    : 0;
70	
71	const quotePremium = (items: Item[], customer: Customer): number => {
72	  const base = basePremium(items);
73	  return (
74	    base
75	    + itemSurcharges(items)
76	    - loyaltyDiscount(base, customer)
77	    + firstInsuranceSurcharge(base)
78	    + PROCESSING_FEE
79	  );
80	};
81	
82	const executeStep = (customer: Customer) => ({ items }: Step) => ({
83	  premium: quotePremium(items, customer),
84	});
85	
86	export const run = (input: unknown): unknown => {
87	  const { customer, steps } = input as Input;
88	  return { results: steps.map(executeStep(customer)) };
89	};
